after_source:
private Request buildRequest(
      Target<TranscodeType> target,
      @Nullable RequestListener<TranscodeType> targetListener,
      BaseRequestOptions<?> requestOptions,
      Executor callbackExecutor) {
    GlideExperiments experiments = glideContext.getExperiments();
    Object requestLock =
        glideContext.getExperiments().isEnabled(FixSingleRequestClearDeadlock.class)
            ? glideContext.getEngine()
            : new Object();
    return buildRequestRecursive(
        requestLock,
        target,
        targetListener,
        /* parentCoordinator= */ null,
        transitionOptions,
        requestOptions.getPriority(),
        requestOptions.getOverrideWidth(),
        requestOptions.getOverrideHeight(),
        requestOptions,
        callbackExecutor);
  }

before_source:
public GlideExecutor build() {
      if (TextUtils.isEmpty(name)) {
        throw new IllegalArgumentException(
            "Name must be non-null and non-empty, but given: " + name);
      }
      ThreadPoolExecutor executor =
          new ThreadPoolExecutor(
              corePoolSize,
              maximumPoolSize,
              /* keepAliveTime= */ threadTimeoutMillis,
              TimeUnit.MILLISECONDS,
              new PriorityBlockingQueue<Runnable>(),
              new DefaultThreadFactory(
                  threadFactory, name, uncaughtThrowableStrategy, preventNetworkOperations));

      if (threadTimeoutMillis != NO_THREAD_TIMEOUT) {
        executor.allowCoreThreadTimeOut(true);
      }

      return new GlideExecutor(executor);
    }

after_source:
public GlideExecutor build() {
      if (TextUtils.isEmpty(name)) {
        throw new IllegalArgumentException(
            "Name must be non-null and non-empty, but given: " + name);
      }
      ThreadFactory factory =
          new DefaultThreadFactory(
              threadFactory, name, uncaughtThrowableStrategy, preventNetworkOperations);
      ThreadPoolExecutor executor;
      if (onExecuteDecorator != null) {
        executor =
            new ThreadPoolExecutor(
                corePoolSize,
                maximumPoolSize,
                /* keepAliveTime= */ threadTimeoutMillis,
                TimeUnit.MILLISECONDS,
                new PriorityBlockingQueue<>(),
                factory) {
              @Override
              public void execute(@NonNull Runnable command) {
                super.execute(onExecuteDecorator.apply(command));
              }
            };
      } else {
        executor =
            new ThreadPoolExecutor(
                corePoolSize,
                maximumPoolSize,
                /* keepAliveTime= */ threadTimeoutMillis,
                TimeUnit.MILLISECONDS,
                new PriorityBlockingQueue<>(),
                factory);
      }

      if (threadTimeoutMillis != NO_THREAD_TIMEOUT) {
        executor.allowCoreThreadTimeOut(true);
      }

      return new GlideExecutor(executor);
    }

