@Override
  public void recycle() {
    synchronized (requestLock) {
      assertNotCallingCallbacks();
      context = null;
      glideContext = null;
      model = null;
      transcodeClass = null;
      requestOptions = null;
      overrideWidth = -1;
      overrideHeight = -1;
      target = null;
      requestListeners = null;
      targetListener = null;
      requestCoordinator = null;
      animationFactory = null;
      loadStatus = null;
      errorDrawable = null;
      placeholderDrawable = null;
      fallbackDrawable = null;
      width = -1;
      height = -1;
      requestOrigin = null;
      POOL.release(this);
    }
    requestLock = null;
  }

