private <T> void loadOnMainThread(final RequestBuilder<T> builder, final Target<T> target) {
    final CountDownLatch latch = new CountDownLatch(1);
    callOnMainThread(
        new Callable<Target<T>>() {
          @Override
          public Target<T> call() {
            builder.into(
                new Target<T>() {
                  @Override
                  public void onStart() {
                    target.onStart();
                  }

                  @Override
                  public void onStop() {
                    target.onStop();
                  }

                  @Override
                  public void onDestroy() {
                    target.onDestroy();
                  }

                  @Override
                  public void onResourceReady(
                      @NonNull T resource, @Nullable Transition<? super T> transition) {
                    target.onResourceReady(resource, transition);
                    if (!Preconditions.checkNotNull(getRequest()).isRunning()) {
                      latch.countDown();
                    }
                  }

                  @Override
                  public void onLoadCleared(@Nullable Drawable placeholder) {
                    target.onLoadCleared(placeholder);
                  }

                  @Override
                  public void onLoadStarted(@Nullable Drawable placeholder) {
                    target.onLoadStarted(placeholder);
                  }

                  @Override
                  public void onLoadFailed(@Nullable Drawable errorDrawable) {
                    target.onLoadFailed(errorDrawable);
                    if (!Preconditions.checkNotNull(getRequest()).isRunning()) {
                      latch.countDown();
                    }
                  }

                  @Override
                  public void getSize(@NonNull SizeReadyCallback cb) {
                    target.getSize(cb);
                  }

                  @Override
                  public void removeCallback(@NonNull SizeReadyCallback cb) {
                    target.removeCallback(cb);
                  }

                  @Override
                  public void setRequest(@Nullable Request request) {
                    target.setRequest(request);
                  }

                  @Nullable
                  @Override
                  public Request getRequest() {
                    return target.getRequest();
                  }
                });
            return target;
          }
        });
    waitOnLatch(latch);
  }

after_source:
private <T> void loadOnMainThread(final RequestBuilder<T> builder, final Target<T> target) {
    final CountDownLatch latch = new CountDownLatch(1);
    callOnMainThread(
        new Callable<Target<T>>() {
          @Override
          public Target<T> call() {
            builder.into(
                new Target<T>() {
                  @Override
                  public void onStart() {
                    target.onStart();
                  }

                  @Override
                  public void onStop() {
                    target.onStop();
                  }

                  @Override
                  public void onDestroy() {
                    target.onDestroy();
                  }

                  @Override
                  public void onResourceReady(
                      @NonNull T resource, @Nullable Transition<? super T> transition) {
                    target.onResourceReady(resource, transition);
                    checkRequestAndMaybeReleaseLatch();
                  }

                  @Override
                  public void onLoadCleared(@Nullable Drawable placeholder) {
                    target.onLoadCleared(placeholder);
                  }

                  @Override
                  public void onLoadStarted(@Nullable Drawable placeholder) {
                    target.onLoadStarted(placeholder);
                  }

                  @Override
                  public void onLoadFailed(@Nullable Drawable errorDrawable) {
                    target.onLoadFailed(errorDrawable);
                    checkRequestAndMaybeReleaseLatch();
                  }

                  @Override
                  public void getSize(@NonNull SizeReadyCallback cb) {
                    target.getSize(cb);
                  }

                  @Override
                  public void removeCallback(@NonNull SizeReadyCallback cb) {
                    target.removeCallback(cb);
                  }

                  @Override
                  public void setRequest(@Nullable Request request) {
                    target.setRequest(request);
                  }

                  @Nullable
                  @Override
                  public Request getRequest() {
                    return target.getRequest();
                  }

                  // We can't guarantee the ordering of when this callback is called and when the
                  // request's state is updated, so it's safer to post the check back to the UI
                  // thread.
                  private void checkRequestAndMaybeReleaseLatch() {
                    Executors.mainThreadExecutor()
                        .execute(
                            new Runnable() {
                              @Override
                              public void run() {
                                if (!Preconditions.checkNotNull(getRequest()).isRunning()) {
                                  latch.countDown();
                                }
                              }
                            });
                  }
                });
            return target;
          }
        });
    waitOnLatch(latch);
  }

