@Override
  public void begin() {
    isPaused = false;
    isRunning = true;
    // If the request has completed previously, there's no need to restart both the full and the
    // thumb, we can just restart the full.
    if (!full.isComplete() && !thumb.isRunning()) {
      thumb.begin();
    }
    if (isRunning && !full.isRunning()) {
      full.begin();
    }
  }

