        return objects.subList(position - 11, position + 1 - 11);
      }

      @Override
      public RequestBuilder<Bitmap> getPreloadRequestBuilder(Object item) {
        assertEquals(objects.get(expectedPosition), item);
        expectedPosition++;
        return mock(RequestBuilder.class);
