        String failHelpMessage =
                  "memoryCacheSize: " + memoryCacheSize
                + " bitmapPoolSize: " + bitmapPoolSize
                + " memoryClass: "    + memoryCacheSize
                + " sizeMultiplier: " + harness.sizeMultiplier;
