before_source:
@Override
	@Nullable
	public Cache getCache(String name) {
		Cache cache = this.caches.get(name);
		if (cache == null) {
			this.caches.computeIfAbsent(name, NoOpCache::new);
			synchronized (this.cacheNames) {
				this.cacheNames.add(name);
			}
		}
		return this.caches.get(name);
	}

