	public InputStream getBody() throws IOException {
		byte[] body = this.body;
		if (body == null) {
			synchronized (this) {
				body = this.body;
				if (body == null) {
					body = StreamUtils.copyToByteArray(this.response.getBody());
					this.body = body;
				}
			}
		}
		return new ByteArrayInputStream(body);
	}

