public void concurrentOperation() {
			if (counter.incrementAndGet() > 2) {
				throw new IllegalStateException();
			}
			try {
				Thread.sleep(10);
			}
			catch (InterruptedException ex) {
				throw new IllegalStateException(ex);
			}
			counter.decrementAndGet();
		}

