@Override
	public void execute(Runnable task) {
		Assert.notNull(task, "Task must not be null");
		if (isThrottleActive()) {
			beforeAccess();
			try {
				task.run();
			}
			finally {
				afterAccess();
			}
		}
		else {
			task.run();
		}
	}

