public void completeWithError(Throwable ex) {
		this.writeLock.lock();
		try {
			this.complete = true;
			this.failure = ex;
			if (this.handler != null) {
				this.handler.completeWithError(ex);
			}
		}
		finally {
			this.writeLock.unlock();
		}
	}

