rivate static Duration toDuration(long value, TimeUnit timeUnit) {
		try {
			return Duration.of(value, timeUnit.toChronoUnit());
		}
		catch (Exception ex) {
			throw new IllegalArgumentException(
					"Unsupported unit " + timeUnit + " for value \"" + value + "\": " + ex.getMessage());
		}
	}

